        if (Double.isNaN(x)) {
            return Double.NaN;
        }
        if (x == Double.NEGATIVE_INFINITY) {
            return 0.0;
        }
        if (x == Double.POSITIVE_INFINITY) {
            return 1.0;
        }
        final double dev = x - mean;
        // Short-circuit for extreme tails to avoid numerical issues in Erf
        if (dev < -20.0 * standardDeviation) {
            return 0.0;
        }
        if (dev > 20.0 * standardDeviation) {
            return 1.0;
